# Batch.fun----
#' @title Batch.fun
#' @description
#' Runs a batch computation of DMTA (surface texture analysis) metrics
#' using the `trident` package. Computes complexity, height, spatial,
#' and topology parameters with optional heterogeneity measures.
#'
#' @param sur Character. Path to the `.sur` file.
#' @param size Numeric. Size of the analysis window (x and y resolution).
#' @param nCell Integer. Number of cells for multi-scale analysis.
#' @param peakRemoval Character or numeric. Controls polynomial surface
#' correction (e.g. "2", "8", or NULL).
#' @param doStd Logical. Whether to compute standardized spatial metrics.
#' @param doComplexity Logical. Compute complexity metrics (ASFC, R2adj).
#' @param doHeight Logical. Compute height parameters.
#' @param doSpatial Logical. Compute spatial parameters.
#' @param doTopology Logical. Compute topological parameters.
#' @param doHComplexity Logical. Compute heterogeneity for complexity.
#' @param doHHeight Logical. Compute heterogeneity for height.
#' @param doHSpatial Logical. Compute heterogeneity for spatial metrics.
#' @param doHTopology Logical. Compute heterogeneity for topology.
#'
#' @return A data.frame containing computed DMTA metrics for the input file.
#' @export
#' @examples
#'
#' sur <- system.file("tests/sur/test_surf2.sur", package = "trident")
#'
#' Mytable <- Batch.fun(sur = sur, size = 256, nCell = 64, peakRemoval = "0",
#'           doStd = TRUE,
#'           doComplexity = TRUE, doHeight = TRUE, doSpatial = TRUE, doTopology = TRUE,
#'           doHComplexity = TRUE, doHHeight = TRUE, doHSpatial = TRUE, doHTopology = TRUE)
#'
#' dplyr::glimpse(Mytable)
Batch.fun <- function(sur, size, nCell, peakRemoval,
                        doStd,
                        doComplexity, doHeight, doSpatial, doTopology,
                        doHComplexity, doHHeight, doHSpatial, doHTopology) {

    TmpDir <- file.path(tempdir(), paste0("worker_", Sys.getpid()))
    dir.create(TmpDir, showWarnings = FALSE)

    if (peakRemoval == "2") {
      trident::polynom.sur(sur, TmpDir = TmpDir, deg = 2)
      sur <- stringr::str_replace(sur, "\\.sur$", "_X1_002_Y1_002.sur")
    }
    if (peakRemoval == "8") {
      trident::polynom.sur(sur, TmpDir = TmpDir, deg = 8)
      sur <- stringr::str_replace(sur, "\\.sur$", "_X1_008_Y1_008.sur")
    }


    # Prepare data frame
    Mytable <- data.frame(File = basename(sur), stringsAsFactors = TRUE)

    # DMTA Computation:
    if (doComplexity) {
      Complexity    <- trident::dmta.asfc(sur = sur, TmpDir = TmpDir, type = "single",
                                          size.x = size, size.y = size)
      
      Mytable$Asfc2 <- Complexity[3]
      Mytable$R2adj <- Complexity[4]
    }
    
    if (doHeight) {
      Elev <- trident::dmta.height(sur = sur, TmpDir = TmpDir, type = "single",
                                   size.x = size, size.y = size)
      
      Mytable$Sa   <- Elev[3]
      Mytable$Sp   <- Elev[4]
      Mytable$Sq   <- Elev[5]
      Mytable$Sv   <- Elev[6]
      Mytable$Ssk  <- Elev[7]
      Mytable$Sku  <- Elev[8]
      Mytable$Sdar <- Elev[9]
      Mytable$Sm   <- Elev[10]
      Mytable$Smd  <- Elev[11]
    }
    
    if (doSpatial) {
      Spat <- trident::dmta.spatial(sur = sur, TmpDir = TmpDir, type = "single",
                                    size.x = size, size.y = size)
      
      Mytable$Rmax <- Spat[3]
      Mytable$Sal  <- Spat[4]
      Mytable$Stri <- Spat[5]
      if (doStd){
      Mytable$Std  <- Spat[6]}
      Mytable$b.sl <- Spat[7]
      Mytable$r.sl <- Spat[8]
      Mytable$s.sl <- Spat[9]
    }
    
    if (doTopology) {
      Topo <- trident::dmta.topology(sur = sur, TmpDir = TmpDir, type = "single",
                                     size.x = size, size.y = size)
      
      Mytable$Sk1  <- Topo[3]
      Mytable$Sk2  <- Topo[4]
      Mytable$Smc1 <- Topo[5]
      Mytable$Smc2 <- Topo[6]
      Mytable$Snb1 <- Topo[7]
      Mytable$Snb2 <- Topo[8]
      Mytable$Sh   <- Topo[9]
    }
    
    # Heterogeneity

    if (doHComplexity) {
      HComplexity <- trident::dmta.asfc(sur = sur, TmpDir = TmpDir, type = "multi",
                                        size.x = size, size.y = size, size.n = nCell)
      
      hTable  <- c(plyr::colwise(trident::trident.hetero)(data.frame(HComplexity[3])))

      Mytable <- data.frame(Mytable, hTable)
    }

    if (doHHeight) {
      HElev <- trident::dmta.height(sur = sur, TmpDir = TmpDir, type = "multi",
                                    size.x = size, size.y = size, size.n = nCell)
      
      hTable  <- c(plyr::colwise(trident::trident.hetero)(data.frame(HElev[3:11])))

      Mytable <- data.frame(Mytable, hTable)
    }

    if (doHSpatial) {
      HSpat <- trident::dmta.spatial(sur = sur, TmpDir = TmpDir, type = "multi",
                                     size.x = size, size.y = size, size.n = nCell)
      
      if ( doStd) {
        hTable <- c(plyr::colwise(trident::trident.hetero)(data.frame(HSpat[3:9]))) }
      if (!doStd) {
        hTable <- c(plyr::colwise(trident::trident.hetero)(data.frame(HSpat[c(3,4,5,7,8,9)]))) }

      Mytable <- data.frame(Mytable, hTable)
    }

    if (doHTopology) {
      HTopo <- trident::dmta.topology(sur = sur, TmpDir = TmpDir, type = "multi",
                                      size.x = size, size.y = size, size.n = nCell)
      
      hTable  <- c(plyr::colwise(trident::trident.hetero)(data.frame(HTopo[3:9])))

      Mytable <- data.frame(Mytable, hTable)
    }

    # Return dataset
    return(Mytable)
  }

# dmta.asfc----
#' @title dmta.asfc
#' @description Computes Asfc variable
#' @param sur surface file
#' @param TmpDir temporary folder
#' @param size.x total x length of the surface, in pixels
#' @param size.y total y length of the surface, in pixels
#' @param size.n in case type = "multi", the number of cells for the calculation of heterogeneity
#' @param type character vector indicating whether a single value should be calculated for the whole surface ("single"); or if multiple values should be calculated for each n cells ("multi")
#' @return A list containing the .sur file, the type (complexity), Asfc2 and R2adj
#' @examples
#' #to do
#' tmp <- tempdir()
#' sur <- system.file("tests/sur/test_surf2.sur", package = "trident")
#'
#' ResAsf <- dmta.asfc(sur = sur, TmpDir = tmp, size.x = 256, 
#'                                              size.y = 256, size.n = 256, type = "single")
#'
#' dplyr::glimpse(ResAsf)
#'
#' @export
dmta.asfc <- function(sur, TmpDir, size.x = 256, size.y = 256, size.n = 256, type = "single") {

  #1-Preparation: move files to tmp
    
  Tmp <- stringr::str_replace_all(TmpDir, "\\\\", "/")
  Sur <- stringr::str_replace_all(sur, "\\\\", "/")

  NameSur <- unlist(strsplit(utils::tail(unlist(strsplit(sur, "\\\\")), 1), ".sur"))

  PrgPath <- system.file("extdata", "structure", "prg", "prg.exe", package = "trident")
  if (PrgPath == "") {PrgPath = "inst/extdata/structure/prg/prg.exe"}
  
  file.copy(from = PrgPath, to = Tmp)

  if (file.exists(file.path(Tmp, 'results_complex.txt'))) {
    file.remove(file.path(Tmp, 'results_complex.txt'))
  }
  
  #2-Recoding
  
  switch(type,
    "single" = {
      Sample.size <- "-0001"
    },
    "multi"  = {
      Sample.size <- paste0("+", size.n)
         },
    stop("type must be 'single' or 'multi'")
  )
  
  #3-Build the scripts

  Myscript <- glue::glue("
VERBOSES
.false.
.false.
'{file.path(Tmp, 'deroulement.txt')}'
 +006
'{file.path(Tmp, 'sortie.txt')}'
DEBUT___
    NB_PROCS
    -1
    LECT_BAS
    '{Sur}'
    .false.
    .false.
    TAB_BOOT
        +{size.x}
        +{size.y}
        {Sample.size}
    STA_LOOP
        +0001 {Sample.size}
        ANALYSES
            'complexi'
            '{file.path(Tmp, 'results_complex.txt')}'
            .true.
            -50
    END_LOOP
FIN_____
")
  
  utils::write.table(Myscript, file = file.path(Tmp, "complex_analysis.f90"), quote = FALSE, row.names = FALSE, col.names = FALSE)

  #4-Run the script
  
  system2(command = file.path(Tmp, "prg.exe"), args = file.path(Tmp, "complex_analysis.f90"), stdout = TRUE)


  #5-Scan and return the results
  
  Scanned  <- scan(file = file.path(Tmp, "results_complex.txt"), what = "character()")

  Results  <- t(matrix(Scanned [-(1:which(stringr::str_detect(Scanned,  "\\.sur")))], nrow = 4))

  idx      <- which(stringr::str_detect(Scanned, "\\.sur"))[1] # to get the index of the line containing the .sur file name,
                                                               # which is the first line of the results file. This is used
                                                               # to extract the file name for the output list.
  Filename <- basename(Scanned[idx])
  
  Asfc <- list(file  = Filename,
               type  = "complexity",
               asfc2 = as.numeric(Results[, 1]),
               r2adj = as.numeric(Results[, 2]))
  
  names(Asfc) <- c("File", "Type", "Asfc2", "R2adj")
  
  return(Asfc)
  
}

