#'                                                     size.y = 256, size.n = 256, type = "multi")
#'
#' dplyr::glimpse(ResHgtMulti)
#'
#' @export
dmta.height <- function(sur, TmpDir, size.x = 256, size.y = 256, size.n = 256, type = "single") {

  #1-Preparation: move files to tmp
    
  Tmp <- stringr::str_replace_all(TmpDir, "\\\\", "/")
  Sur <- stringr::str_replace_all(sur, "\\\\", "/")

  NameSur <- unlist(strsplit(utils::tail(unlist(strsplit(sur, "\\\\")), 1), ".sur"))

  PrgPath <- system.file("extdata", "structure", "prg", "prg.exe", package = "trident")
  if (PrgPath == "") {PrgPath = "inst/extdata/structure/prg/prg.exe"}
  
  file.copy(from = PrgPath, to = Tmp)

  if (file.exists(file.path(Tmp, 'results_height.txt'))) {
    file.remove(file.path(Tmp, 'results_height.txt'))
  }

  if (file.exists(file.path(Tmp, 'results_faces.txt'))) {
    file.remove(file.path(Tmp, 'results_faces.txt'))
  }
  
  #2-Recoding
  
  switch(type,
    "single" = {
      Sample.size <- "-0001"
    },
    "multi"  = {
      Sample.size <- paste0("+", size.n)
         },
    stop("type must be 'single' or 'multi'")
  )
  
  #3-Build the scripts

  Myscript <- glue::glue("
VERBOSES
.false.
.false.
'{file.path(Tmp, 'deroulement.txt')}'
 +006
'{file.path(Tmp, 'sortie.txt')}'
DEBUT___
    NB_PROCS
    -1
    LECT_BAS
    '{Sur}'
    .false.
    .false.
    TAB_BOOT
        +{size.x}
        +{size.y}
        {Sample.size}
    STA_LOOP
        +0001 {Sample.size}
        ANALYSES
            'statisti'
            '{file.path(Tmp, 'results_height.txt')}'
            .true.
            -50
    END_LOOP
    TAB_BOOT
        +{size.x}
        +{size.y}
        {Sample.size}
    STA_LOOP
        +0001 {Sample.size}
        ANALYSES
            'facettes'
            '{file.path(Tmp, 'results_faces.txt')}'
            .true.
            -50
    END_LOOP
FIN_____
")

  utils::write.table(Myscript, file = file.path(Tmp, "height_analysis.f90"), quote = FALSE, row.names = FALSE, col.names = FALSE)

  #4-Run the script
  
  system2(command = file.path(Tmp, "prg.exe"), args = file.path(Tmp, "height_analysis.f90"), stdout = TRUE)


  #5-Scan and return the results
  
  Scanned  <- scan(file = file.path(Tmp, "results_height.txt"), what = "character()")
  Scanned2 <- scan(file = file.path(Tmp, "results_faces.txt"),  what = "character()")
  
  Results  <- t(matrix(Scanned [-(1:which(stringr::str_detect(Scanned,  "\\.sur")))], nrow = 16))
  Results2 <- t(matrix(Scanned2[-(1:which(stringr::str_detect(Scanned2, "\\.sur")))], nrow =  4))
  
  idx      <- which(stringr::str_detect(Scanned, "\\.sur"))[1] # to get the index of the line containing the .sur file name,
                                                               # which is the first line of the results file. This is used
                                                               # to extract the file name for the output list.
  Filename <- basename(Scanned[idx])
  
  Height <- list(file = Filename,
                 type = "height",
                 Sa   = as.numeric(Results [, 4]),
                 Sp   = as.numeric(Results [, 2]),
                 Sq   = as.numeric(Results [, 6]),
                 Sv   = as.numeric(Results [, 1]),
                 Ssk  = as.numeric(Results [, 7]),
                 Sku  = as.numeric(Results [, 8]),
                 Sdar = as.numeric(Results2[, 2]),
                 Sm   = as.numeric(Results [, 5]),
                 Smd  = as.numeric(Results [, 3]))
  
  names(Height) <- c("File", "Type", "Sa", "Sp", "Sq", "Sv", "Ssk", "Sku", "Sdar", "Sm", "Smd")
  
  return(Height)
}

# dmta.spatial----
#' @title dmta.spatial
#' @description Computes spatial variables
#' @param sur surface file
#' @param TmpDir temporary folder
#' @param size.x total x length of the surface, in pixels
#' @param size.y total y length of the surface, in pixels
#' @param size.n in case type = "multi", the number of cells for the calculation of heterogeneity
#' @param type character vector indicating whether a single value should be calculated for the whole surface ("single"); or if multiple values should be calculated for each n cells ("multi")
#' @return A list containing the .sur file, the type (spatial), Rmax, Sal, Stri, Std, b.sl, r.sl and s.sl
#' @examples
#' #to do
#' tmp <- tempdir()
#' sur <- system.file("tests/sur/test_surf.sur", package = "trident")
#'
#' ResSpt <- dmta.spatial(sur = sur, TmpDir = tmp, size.x = 256,
#'                                                 size.y = 256, size.n = 256, type = "single")
#'
#' dplyr::glimpse(ResSpt)
#'
#' ResSptMulti <- dmta.spatial(sur = sur, TmpDir = tmp, size.x = 256,
#'                                                      size.y = 256, size.n = 256, type = "multi")
#'
#' dplyr::glimpse(ResSptMulti)
#'
#' @export
dmta.spatial <- function(sur, TmpDir, size.x = 256, size.y = 256, size.n = 256, type = "single") {

  #1-Preparation: move files to tmp
    
  Tmp <- stringr::str_replace_all(TmpDir, "\\\\", "/")
  Sur <- stringr::str_replace_all(sur, "\\\\", "/")

  NameSur <- unlist(strsplit(utils::tail(unlist(strsplit(sur, "\\\\")), 1), ".sur"))

  PrgPath <- system.file("extdata", "structure", "prg", "prg.exe", package = "trident")
  if (PrgPath == "") {PrgPath = "inst/extdata/structure/prg/prg.exe"}
  
  file.copy(from = PrgPath, to = Tmp)

  if (file.exists(file.path(Tmp, 'results_spatial.txt'))) {
    file.remove(file.path(Tmp, 'results_spatial.txt'))
  }
  
  #2-Recoding
  
  switch(type,
    "single" = {
      Sample.size <- "-0001"
    },
    "multi"  = {
      Sample.size <- paste0("+", size.n)
         },
    stop("type must be 'single' or 'multi'")
  )
  
  #3-Build the scripts

  Myscript <- glue::glue("
VERBOSES
.false.
.false.
'{file.path(Tmp, 'deroulement.txt')}'
 +006
'{file.path(Tmp, 'sortie.txt')}'
DEBUT___
    NB_PROCS
    -1
    LECT_BAS
    '{Sur}'
    .false.
    .false.
    TAB_BOOT
        +{size.x}
        +{size.y}
        {Sample.size}
    STA_LOOP
        +0001 {Sample.size}
        ANALYSES
            'elli_acv'
            '{file.path(Tmp, 'results_spatial.txt')}'
            .true.
            -50
    END_LOOP
FIN_____
")

  utils::write.table(Myscript, file = file.path(Tmp, "spatial_analysis.f90"), quote = FALSE, row.names = FALSE, col.names = FALSE)

  #4-Run the script
  
  system2(command = file.path(Tmp, "prg.exe"), args = file.path(Tmp, "spatial_analysis.f90"), stdout = TRUE)


  #5-Scan and return the results
  
  Scanned  <- scan(file = file.path(Tmp, "results_spatial.txt"), what = "character()")

  Results  <- t(matrix(Scanned [-(1:which(stringr::str_detect(Scanned,  "\\.sur")))], nrow = 16))
  # to remove the first lines of the results file, which contain the .sur file name and the column names.
  # The remaining lines are then reshaped into a matrix with 16 columns (one for each variable) and as many rows as there
  # are samples (1 if type = "single", or size.n if type = "multi").

  idx      <- which(stringr::str_detect(Scanned, "\\.sur"))[1] # to get the index of the line containing the .sur file name,
                                                               # which is the first line of the results file. This is used
                                                               # to extract the file name for the output list.
  Filename <- basename(Scanned[idx])

  Spatial <- list(file = Filename,
                  type = "spatial",
                  rmax = as.numeric(Results[, 1]),
                  sal  = as.numeric(Results[, 2]),
                  stri = as.numeric(Results[, 3]),
                  std  = as.numeric(Results[, 4]),
                  b.sl = as.numeric(Results[, 6]),
                  r.sl = as.numeric(Results[, 7]),
                  s.sl = as.numeric(Results[, 5]))

  names(Spatial) <- c("File", "Type", "Rmax", "Sal", "Stri", "Std", "b.sl", "r.sl", "s.sl")
  
  return(Spatial)
}

